{
  "lessons": [
    {
      "concepts": [
        "Sequence Modeling Limits",
        "Recurrence Bottleneck",
        "Convolution Receptive Path",
        "Parallel Token Processing"
      ],
      "description": "See the concrete training and scaling problems that made older sequence models hard to push further. These ideas make the transformer feel like a practical answer to real bottlenecks, not just a new buzzword.",
      "title": "Why older sequence models hit a wall"
    },
    {
      "concepts": [
        "Token Embeddings",
        "Subword Tokens",
        "Vocabulary Matrix",
        "Embedding Dimension",
        "Learned Embeddings"
      ],
      "description": "Start with how raw text becomes vectors a model can work with. Keep the focus on the specific objects that enter a transformer before attention begins.",
      "title": "Turning tokens into vectors"
    },
    {
      "concepts": [
        "Positional Encoding",
        "Sinusoidal Positions",
        "Learned Position Embeddings",
        "Position Information Loss"
      ],
      "description": "Track how a transformer knows token order even though it processes tokens in parallel. This is the missing ingredient that keeps a bag of vectors from losing sequence structure.",
      "title": "Giving order to parallel tokens"
    },
    {
      "concepts": [
        "Query Vector",
        "Key Vector",
        "Value Vector",
        "Attention Score",
        "Scaled Dot Product"
      ],
      "description": "Follow the exact pieces used to decide which tokens matter to each other. These are the core objects behind the attention computation.",
      "title": "Reading attention scores step by step"
    },
    {
      "concepts": [
        "Softmax Weights",
        "Attention Output",
        "Attention Weight Matrix",
        "Self-Attention",
        "Cross-Attention"
      ],
      "description": "Move from raw similarity scores to the weighted mixtures that become new token representations. This is the point where attention turns comparisons into useful information flow.",
      "title": "Turning scores into context"
    },
    {
      "concepts": [
        "Multiple Attention Heads",
        "Head Specialization",
        "Head Concatenation",
        "Output Projection"
      ],
      "description": "Look at why one attention pattern is usually not enough. Multiple heads let the model track different relations at the same time before mixing them back together.",
      "title": "Using many attention views at once"
    },
    {
      "concepts": [
        "Position-Wise Feedforward Network",
        "Residual Connection",
        "Layer Normalization",
        "Dropout in Transformers"
      ],
      "description": "Attention is only part of the block. These components stabilize training, add nonlinearity, and help each layer refine what attention has gathered.",
      "title": "Building a transformer block"
    },
    {
      "concepts": [
        "Encoder Stack",
        "Bidirectional Context",
        "Encoder Representation"
      ],
      "description": "Focus on the encoder as a stack that builds context-rich token representations from the full input. This is the side of the architecture used heavily for understanding tasks.",
      "title": "Building context with the encoder"
    },
    {
      "concepts": [
        "Decoder Stack",
        "Causal Mask",
        "Autoregressive Prediction",
        "Shifted Targets"
      ],
      "description": "Follow how the decoder generates one token at a time without peeking ahead. These mechanics are central to sequence generation in transformer models.",
      "title": "Generating tokens with the decoder"
    },
    {
      "concepts": [
        "Encoder-Decoder Attention",
        "Source Memory",
        "Target Prefix",
        "Sequence-to-Sequence Mapping"
      ],
      "description": "Connect the encoder and decoder into one system that reads an input sequence and writes an output sequence. This is the pattern behind translation and many other structured generation tasks.",
      "title": "Linking input text to output text"
    },
    {
      "concepts": [
        "Padding Mask",
        "Look-Ahead Mask",
        "Masked Attention Weights"
      ],
      "description": "Masks control which positions may interact during attention. Get clear on the exact restrictions that keep batching efficient and generation valid.",
      "title": "Controlling what each token can see"
    },
    {
      "concepts": [
        "Transformer Depth",
        "Hidden Size",
        "Attention Head Count",
        "Feedforward Width"
      ],
      "description": "These are the main knobs that shape transformer capacity and compute cost. Learn what each one changes inside the network.",
      "title": "Choosing the model’s main dimensions"
    },
    {
      "concepts": [
        "Training Objective",
        "Next Token Prediction",
        "Masked Language Modeling",
        "Denoising Objective",
        "Teacher Forcing"
      ],
      "description": "Map the main learning targets used to pretrain transformer models. Each objective pushes the architecture toward a different kind of representation or generation skill.",
      "title": "Training transformers with the right target"
    },
    {
      "concepts": [
        "BERT",
        "GPT",
        "T5",
        "Vision Transformer",
        "Whisper"
      ],
      "description": "Anchor the chapter in the model families people actually name in practice. Each one reflects a concrete transformer pattern that spread across real-world ML.",
      "title": "Recognizing the transformer families people use"
    },
    {
      "concepts": [
        "Encoder-Only Models",
        "Decoder-Only Models",
        "Encoder-Decoder Models"
      ],
      "description": "Sort the major transformer layouts by what part of the stack they keep. This helps connect architecture choices to the tasks they fit best.",
      "title": "Picking the right transformer layout"
    },
    {
      "concepts": [
        "Pretraining",
        "Fine-Tuning",
        "Instruction Tuning",
        "Transfer Learning"
      ],
      "description": "Place transformers in the modern training pipeline where general knowledge is learned first and then adapted. This is the pattern that made large reusable models practical.",
      "title": "Adapting pretrained transformers"
    },
    {
      "concepts": [
        "Attention Complexity",
        "Quadratic Memory Growth",
        "Long Context Cost",
        "KV Cache"
      ],
      "description": "Face the concrete compute limits that appear when sequences get long. These ideas matter because transformer power comes with real memory and latency tradeoffs.",
      "title": "Understanding why long sequences get expensive"
    },
    {
      "concepts": [
        "Sparse Attention",
        "Linear Attention",
        "FlashAttention",
        "Sliding Window Attention"
      ],
      "description": "Look at modern techniques that make attention cheaper or faster in practice. These methods matter because today's transformer work depends on more than the original paper.",
      "title": "Making attention cheaper in practice"
    },
    {
      "concepts": [
        "Vision Patches",
        "Patch Embedding",
        "Class Token",
        "Image Positional Embeddings"
      ],
      "description": "See how images are turned into transformer inputs without convolutional feature maps. The image becomes a sequence of patch vectors that the model can attend over.",
      "title": "Reading images as token sequences"
    },
    {
      "concepts": [
        "Spectrogram Tokens",
        "Audio Frames",
        "Multimodal Tokens"
      ],
      "description": "Extend the same sequence idea beyond text. Audio and mixed-modality systems work by turning different signals into tokens that can share a transformer backbone.",
      "title": "Turning audio and multimodal data into tokens"
    },
    {
      "concepts": [
        "Global Dependency Modeling",
        "Gradient Path Length",
        "In-Context Interaction",
        "Scaling Behavior"
      ],
      "description": "Pin down the specific advantages that helped transformers replace many earlier architectures. These are the properties practitioners noticed when models got bigger and tasks got broader.",
      "title": "Seeing why transformers replaced older architectures"
    },
    {
      "concepts": [
        "Attention Pattern Interpretation",
        "Attention Map",
        "Representation Probing",
        "Emergent Features"
      ],
      "description": "Study the main ways people inspect what transformers learn inside their layers and heads. This gives a grounded view of interpretability without drifting into product-level LLM behavior.",
      "title": "Inspecting what a transformer learned"
    }
  ]
}
